using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class Tools
{
    [McpServerTool, Description("Echoes a message back with a timestamp.")]
    public static string Echo(
        [Description("The message to echo")] string message) =>
        $"[{DateTime.UtcNow:O}] {message}";

    [McpServerTool, Description("Adds two numbers together.")]
    public static double Add(
        [Description("First number")] double a,
        [Description("Second number")] double b) =>
        a + b;
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class Resources
{
    [McpServerResource(
        UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the application configuration data.")]
    public static string GetAppConfig() =>
        JsonSerializer.Serialize(new
        {
            AppName = "HttpMcpServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxRetries = 3,
            TimeoutSeconds = 30
        }, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(
        UriTemplate = "config://features",
        Name = "Feature Flags",
        MimeType = "application/json"),
     Description("Returns current feature flag settings.")]
    public static string GetFeatureFlags() =>
        JsonSerializer.Serialize(new
        {
            EnableCaching = true,
            EnableNotifications = false,
            MaxUploadSizeMb = 50
        }, new JsonSerializerOptions { WriteIndented = true });
}

